  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject } from '../domain/sketchModels';
  3→import { sanitizePartDimensions, sanitizePartPosition } from '../domain/validation';
  4→import { resolveConstraints } from '../domain/constraintResolver';
  5→import { updateBoundDimensionEndpoints } from '../domain/dimensionBinding';
  6→import { generateId } from '@/domain/ids';
  7→import { getTemplate } from '../domain/templates/templateRegistry';
  8→import { createTemplateAssembly } from '../domain/assemblyModels';
  9→
 10→const SketchContext = createContext(null);
 11→const HISTORY_LIMIT = 80;
 12→
 13→function snapshotSketch(sketchProject) {
 14→  return JSON.stringify(sketchProject);
 15→}
 16→
 17→function applyUpdate(state, nextProject, recordHistory = true) {
 18→  const nextSnapshot = snapshotSketch(nextProject);
 19→  const history = recordHistory
 20→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 21→    : state.history;
 22→
 23→  return {
 24→    ...state,
 25→    history,
 26→    future: recordHistory ? [] : state.future,
 27→    project: nextProject,
 28→    isDirty: nextSnapshot !== state.savedSnapshot,
 29→  };
 30→}
 31→
 32→function mergePart(existing, updates) {
 33→  const merged = { ...existing, ...updates };
 34→  // Deep-merge position and rotation
 35→  if (updates.position) {
 36→    merged.position = { ...existing.position, ...updates.position };
 37→  }
 38→  if (updates.rotation) {
 39→    merged.rotation = { ...existing.rotation, ...updates.rotation };
 40→  }
 41→  return merged;
 42→}
 43→
 44→function sanitizePart(part) {
 45→  if (part.type === 'dimension') return part;
 46→  return sanitizePartPosition(sanitizePartDimensions(part));
 47→}
 48→
 49→function applyConstraints(project) {
 50→  const constraints = project.constraints || [];
 51→  if (constraints.length === 0) return project;
 52→
 53→  const resolved = resolveConstraints(constraints, project.parts);
 54→  if (resolved.size === 0) return project;
 55→
 56→  return {
 57→    ...project,
 58→    parts: project.parts.map((p) => {
 59→      const newPos = resolved.get(p.id);
 60→      return newPos ? { ...p, position: newPos } : p;
 61→    }),
 62→  };
 63→}
 64→
 65→function updateBoundDimensions(project, updatedPartId) {
 66→  const updatedPart = project.parts.find((p) => p.id === updatedPartId);
 67→  if (!updatedPart) return project;
 68→
 69→  let changed = false;
 70→  const newParts = project.parts.map((p) => {
 71→    if (p.type === 'dimension' && p.boundPartId === updatedPartId) {
 72→      changed = true;
 73→      return updateBoundDimensionEndpoints(p, updatedPart);
 74→    }
 75→    return p;
 76→  });
 77→
 78→  return changed ? { ...project, parts: newParts } : project;
 79→}
 80→
 81→function clonePart(part, idMap) {
 82→  const newId = generateId('part');
 83→  idMap.set(part.id, newId);
 84→  return {
 85→    ...part,
 86→    id: newId,
 87→    name: `${part.name} (copy)`,
 88→    position: {
 89→      ...part.position,
 90→      x: part.position.x + 50,
 91→      y: part.position.y + 50,
 92→    },
 93→  };
 94→}
 95→
 96→function sketchReducer(state, action) {
 97→  switch (action.type) {
 98→    case 'SKETCH_NEW': {
 99→      const newProject = action.project || createSketchProject();
100→      return {
101→        project: newProject,
102→        isDirty: false,
103→        savedSnapshot: snapshotSketch(newProject),
104→        history: [],
105→        future: [],
106→      };
107→    }
108→
109→    case 'SKETCH_LOAD': {
110→      const loaded = action.project;
111→      return {
112→        project: loaded,
113→        isDirty: false,
114→        savedSnapshot: snapshotSketch(loaded),
115→        history: [],
116→        future: [],
117→      };
118→    }
119→
120→    case 'PART_ADD': {
121→      const part = sanitizePart(action.part);
122→      let nextProject = {
123→        ...state.project,
124→        updatedAt: new Date().toISOString(),
125→        parts: [...state.project.parts, part],
126→      };
127→      nextProject = applyConstraints(nextProject);
128→      return applyUpdate(state, nextProject);
129→    }
130→
131→    case 'PART_UPDATE': {
132→      let nextProject = {
133→        ...state.project,
134→        updatedAt: new Date().toISOString(),
135→        parts: state.project.parts.map((p) => {
136→          if (p.id !== action.part.id) return p;
137→          const merged = mergePart(p, action.part);
138→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
139→        }),
140→      };
141→      nextProject = applyConstraints(nextProject);
142→      nextProject = updateBoundDimensions(nextProject, action.part.id);
143→      return applyUpdate(state, nextProject);
144→    }
145→
146→    case 'PART_DELETE': {
147→      const partId = action.partId;
148→      // Also remove child parts (cutouts/holes with this parentId)
149→      const childIds = new Set(
150→        state.project.parts.filter((p) => p.parentId === partId).map((p) => p.id)
151→      );
152→      const idsToRemove = new Set([partId, ...childIds]);
153→
154→      // Also remove constraints referencing deleted parts
155→      const constraints = (state.project.constraints || []).filter(
156→        (c) => !idsToRemove.has(c.sourcePartId) && !idsToRemove.has(c.targetPartId)
157→      );
158→
159→      // Also remove dimensions bound to deleted parts
160→      return applyUpdate(state, {
161→        ...state.project,
162→        updatedAt: new Date().toISOString(),
163→        parts: state.project.parts
164→          .filter((p) => !idsToRemove.has(p.id))
165→          .map((p) => {
166→            if (p.type === 'dimension' && p.boundPartId && idsToRemove.has(p.boundPartId)) {
167→              return { ...p, boundPartId: null, boundProperty: null, boundAxis: null };
168→            }
169→            return p;
170→          }),
171→        assemblies: state.project.assemblies.map((asm) => ({
172→          ...asm,
173→          partIds: asm.partIds.filter((id) => !idsToRemove.has(id)),
174→        })),
175→        constraints,
176→      });
177→    }
178→
179→    case 'PART_CLONE': {
180→      const partId = action.partId;
181→      const part = state.project.parts.find((p) => p.id === partId);
182→      if (!part) return state;
183→
184→      const idMap = new Map();
185→      const cloned = clonePart(part, idMap);
186→
187→      // Clone children (cutouts/holes with matching parentId)
188→      const children = state.project.parts.filter((p) => p.parentId === partId);
189→      const clonedChildren = children.map((child) => {
190→        const clonedChild = clonePart(child, idMap);
191→        clonedChild.parentId = cloned.id;
192→        return clonedChild;
193→      });
194→
195→      const newParts = [cloned, ...clonedChildren];
196→
197→      // Add to same assembly if applicable
198→      let assemblies = state.project.assemblies;
199→      if (part.assemblyId) {
200→        assemblies = assemblies.map((asm) => {
201→          if (asm.id === part.assemblyId) {
202→            return {
203→              ...asm,
204→              partIds: [...asm.partIds, ...newParts.map((p) => p.id)],
205→            };
206→          }
207→          return asm;
208→        });
209→        // Set assemblyId on clones
210→        for (const np of newParts) {
211→          np.assemblyId = part.assemblyId;
212→        }
213→      }
214→
215→      return applyUpdate(state, {
216→        ...state.project,
217→        updatedAt: new Date().toISOString(),
218→        parts: [...state.project.parts, ...newParts],
219→        assemblies,
220→      });
221→    }
222→
223→    case 'ASSEMBLY_ADD':
224→      return applyUpdate(state, {
225→        ...state.project,
226→        updatedAt: new Date().toISOString(),
227→        assemblies: [...state.project.assemblies, action.assembly],
228→      });
229→
230→    case 'ASSEMBLY_UPDATE':
231→      return applyUpdate(state, {
232→        ...state.project,
233→        updatedAt: new Date().toISOString(),
234→        assemblies: state.project.assemblies.map((asm) =>
235→          asm.id === action.assembly.id ? { ...asm, ...action.assembly } : asm
236→        ),
237→      });
238→
239→    case 'ASSEMBLY_DELETE': {
240→      const asmId = action.assemblyId;
241→      return applyUpdate(state, {
242→        ...state.project,
243→        updatedAt: new Date().toISOString(),
244→        assemblies: state.project.assemblies.filter((asm) => asm.id !== asmId),
245→        parts: state.project.parts.map((p) =>
246→          p.assemblyId === asmId ? { ...p, assemblyId: null } : p
247→        ),
248→      });
249→    }
250→
251→    case 'ASSEMBLY_ADD_PART': {
252→      const { assemblyId, partId } = action;
253→      return applyUpdate(state, {
254→        ...state.project,
255→        updatedAt: new Date().toISOString(),
256→        assemblies: state.project.assemblies.map((asm) =>
257→          asm.id === assemblyId && !asm.partIds.includes(partId)
258→            ? { ...asm, partIds: [...asm.partIds, partId] }
259→            : asm
260→        ),
261→        parts: state.project.parts.map((p) =>
262→          p.id === partId ? { ...p, assemblyId } : p
263→        ),
264→      });
265→    }
266→
267→    case 'ASSEMBLY_REMOVE_PART': {
268→      const { assemblyId, partId } = action;
269→      return applyUpdate(state, {
270→        ...state.project,
271→        updatedAt: new Date().toISOString(),
272→        assemblies: state.project.assemblies.map((asm) =>
273→          asm.id === assemblyId
274→            ? { ...asm, partIds: asm.partIds.filter((id) => id !== partId) }
275→            : asm
276→        ),
277→        parts: state.project.parts.map((p) =>
278→          p.id === partId && p.assemblyId === assemblyId ? { ...p, assemblyId: null } : p
279→        ),
280→      });
281→    }
282→
283→    case 'ASSEMBLY_CLONE': {
284→      const asmId = action.assemblyId;
285→      const asm = state.project.assemblies.find((a) => a.id === asmId);
286→      if (!asm) return state;
287→
288→      const idMap = new Map();
289→      const newAsmId = generateId('asm');
290→      const newAsm = {
291→        ...asm,
292→        id: newAsmId,
293→        name: `${asm.name} (copy)`,
294→        partIds: [],
295→      };
296→
297→      // Clone all parts in this assembly
298→      const asmParts = state.project.parts.filter((p) => p.assemblyId === asmId);
299→      const clonedParts = [];
300→
301→      for (const part of asmParts) {
302→        const cloned = clonePart(part, idMap);
303→        cloned.assemblyId = newAsmId;
304→        clonedParts.push(cloned);
305→      }
306→
307→      // Fix parentId references
308→      for (const cp of clonedParts) {
309→        if (cp.parentId && idMap.has(cp.parentId)) {
310→          cp.parentId = idMap.get(cp.parentId);
311→        }
312→      }
313→
314→      newAsm.partIds = clonedParts.map((p) => p.id);
315→
316→      return applyUpdate(state, {
317→        ...state.project,
318→        updatedAt: new Date().toISOString(),
319→        parts: [...state.project.parts, ...clonedParts],
320→        assemblies: [...state.project.assemblies, newAsm],
321→      });
322→    }
323→
324→    case 'CONSTRAINT_ADD': {
325→      const constraints = [...(state.project.constraints || []), action.constraint];
326→      let nextProject = {
327→        ...state.project,
328→        updatedAt: new Date().toISOString(),
329→        constraints,
330→      };
331→      nextProject = applyConstraints(nextProject);
332→      return applyUpdate(state, nextProject);
333→    }
334→
335→    case 'CONSTRAINT_UPDATE': {
336→      const constraints = (state.project.constraints || []).map((c) =>
337→        c.id === action.constraint.id ? { ...c, ...action.constraint } : c
338→      );
339→      let nextProject = {
340→        ...state.project,
341→        updatedAt: new Date().toISOString(),
342→        constraints,
343→      };
344→      nextProject = applyConstraints(nextProject);
345→      return applyUpdate(state, nextProject);
346→    }
347→
348→    case 'CONSTRAINT_DELETE': {
349→      const constraints = (state.project.constraints || []).filter(
350→        (c) => c.id !== action.constraintId
351→      );
352→      return applyUpdate(state, {
353→        ...state.project,
354→        updatedAt: new Date().toISOString(),
355→        constraints,
356→      });
357→    }
358→
359→    case 'ANNOTATION_ADD':
360→      return applyUpdate(state, {
361→        ...state.project,
362→        updatedAt: new Date().toISOString(),
363→        annotations: [...(state.project.annotations || []), action.annotation],
364→      });
365→
366→    case 'ANNOTATION_UPDATE':
367→      return applyUpdate(state, {
368→        ...state.project,
369→        updatedAt: new Date().toISOString(),
370→        annotations: (state.project.annotations || []).map((a) =>
371→          a.id === action.annotation.id ? { ...a, ...action.annotation } : a
372→        ),
373→      });
374→
375→    case 'ANNOTATION_DELETE':
376→      return applyUpdate(state, {
377→        ...state.project,
378→        updatedAt: new Date().toISOString(),
379→        annotations: (state.project.annotations || []).filter((a) => a.id !== action.annotationId),
380→      });
381→
382→    case 'PROJECT_UPDATE_META':
383→      return applyUpdate(state, {
384→        ...state.project,
385→        updatedAt: new Date().toISOString(),
386→        ...action.meta,
387→      });
388→
389→    case 'SKETCH_SHEET_ADD':
390→      return applyUpdate(state, {
391→        ...state.project,
392→        updatedAt: new Date().toISOString(),
393→        sheets: [...(state.project.sheets || []), action.sheet],
394→      });
395→
396→    case 'SKETCH_SHEET_UPDATE':
397→      return applyUpdate(state, {
398→        ...state.project,
399→        updatedAt: new Date().toISOString(),
400→        sheets: (state.project.sheets || []).map((s) =>
401→          s.id === action.sheet.id ? { ...s, ...action.sheet } : s
402→        ),
403→      });
404→
405→    case 'SKETCH_SHEET_DELETE':
406→      return applyUpdate(state, {
407→        ...state.project,
408→        updatedAt: new Date().toISOString(),
409→        sheets: (state.project.sheets || []).filter((s) => s.id !== action.sheetId),
410→      });
411→
412→    case 'SKETCH_SHEET_VIEWPORT_ADD': {
413→      const targetSheet = (state.project.sheets || []).find((s) => s.id === action.sheetId);
414→      if (!targetSheet) return state;
415→      return applyUpdate(state, {
416→        ...state.project,
417→        updatedAt: new Date().toISOString(),
418→        sheets: state.project.sheets.map((s) =>
419→          s.id === action.sheetId
420→            ? { ...s, viewports: [...(s.viewports || []), action.viewport] }
421→            : s
422→        ),
423→      });
424→    }
425→
426→    case 'SKETCH_SHEET_VIEWPORT_UPDATE': {
427→      return applyUpdate(state, {
428→        ...state.project,
429→        updatedAt: new Date().toISOString(),
430→        sheets: (state.project.sheets || []).map((s) =>
431→          s.id === action.sheetId
432→            ? {
433→                ...s,
434→                viewports: (s.viewports || []).map((vp) =>
435→                  vp.id === action.viewport.id ? { ...vp, ...action.viewport } : vp
436→                ),
437→              }
438→            : s
439→        ),
440→      });
441→    }
442→
443→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
444→      return applyUpdate(state, {
445→        ...state.project,
446→        updatedAt: new Date().toISOString(),
447→        sheets: (state.project.sheets || []).map((s) =>
448→          s.id === action.sheetId
449→            ? { ...s, viewports: (s.viewports || []).filter((vp) => vp.id !== action.viewportId) }
450→            : s
451→        ),
452→      });
453→
454→    case 'TEMPLATE_GENERATE': {
455→      const template = getTemplate(action.templateType);
456→      if (!template) return state;
457→      const { parts, name } = template.generate(action.params);
458→      const assembly = createTemplateAssembly(action.templateType, action.params, name);
459→      if (action.assemblyId) assembly.id = action.assemblyId;
460→      for (const part of parts) {
461→        part.assemblyId = assembly.id;
462→      }
463→      assembly.partIds = parts.map((p) => p.id);
464→      return applyUpdate(state, {
465→        ...state.project,
466→        updatedAt: new Date().toISOString(),
467→        parts: [...state.project.parts, ...parts.map(sanitizePart)],
468→        assemblies: [...state.project.assemblies, assembly],
469→      });
470→    }
471→
472→    case 'TEMPLATE_REGENERATE': {
473→      const asm = state.project.assemblies.find((a) => a.id === action.assemblyId);
474→      if (!asm || !asm.templateType) return state;
475→      const template = getTemplate(asm.templateType);
476→      if (!template) return state;
477→
478→      const oldPartIds = new Set(asm.partIds);
479→
480→      // Remove constraints referencing old parts
481→      const constraints = (state.project.constraints || []).filter(
482→        (c) => !oldPartIds.has(c.sourcePartId) && !oldPartIds.has(c.targetPartId)
483→      );
484→
485→      // Unbind dimensions bound to old parts, remove old parts
486→      const remainingParts = state.project.parts
487→        .filter((p) => !oldPartIds.has(p.id))
488→        .map((p) => {
489→          if (p.type === 'dimension' && p.boundPartId && oldPartIds.has(p.boundPartId)) {
490→            return { ...p, boundPartId: null, boundProperty: null, boundAxis: null };
491→          }
492→          return p;
493→        });
494→
495→      // Generate new parts
496→      const { parts: newParts } = template.generate(action.params);
497→      for (const part of newParts) {
498→        part.assemblyId = asm.id;
499→      }
500→
501→      const updatedAsm = {
502→        ...asm,
503→        partIds: newParts.map((p) => p.id),
504→        templateParams: { ...action.params },
505→      };
506→
507→      return applyUpdate(state, {
508→        ...state.project,
509→        updatedAt: new Date().toISOString(),
510→        parts: [...remainingParts, ...newParts.map(sanitizePart)],
511→        assemblies: state.project.assemblies.map((a) => (a.id === asm.id ? updatedAsm : a)),
512→        constraints,
513→      });
514→    }
515→
516→    case 'TEMPLATE_DETACH': {
517→      return applyUpdate(state, {
518→        ...state.project,
519→        updatedAt: new Date().toISOString(),
520→        assemblies: state.project.assemblies.map((a) =>
521→          a.id === action.assemblyId
522→            ? { ...a, templateType: null, templateParams: null }
523→            : a
524→        ),
525→      });
526→    }
527→
528→    case 'UNDO': {
529→      if (state.history.length === 0) return state;
530→      const previous = state.history[state.history.length - 1];
531→      return {
532→        ...state,
533→        project: previous,
534→        history: state.history.slice(0, -1),
535→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
536→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
537→      };
538→    }
539→
540→    case 'REDO': {
541→      if (state.future.length === 0) return state;
542→      const next = state.future[0];
543→      return {
544→        ...state,
545→        project: next,
546→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
547→        future: state.future.slice(1),
548→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
549→      };
550→    }
551→
552→    case 'MARK_SAVED':
553→      return {
554→        ...state,
555→        isDirty: false,
556→        savedSnapshot: snapshotSketch(state.project),
557→      };
558→
559→    default:
560→      return state;
561→  }
562→}
563→
564→function createInitialState(project) {
565→  return {
566→    project,
567→    isDirty: false,
568→    savedSnapshot: snapshotSketch(project),
569→    history: [],
570→    future: [],
571→  };
572→}
573→
574→export function SketchProvider({ children, initialProject }) {
575→  const [state, dispatch] = useReducer(
576→    sketchReducer,
577→    initialProject || createSketchProject(),
578→    createInitialState
579→  );
580→
581→  return (
582→    <SketchContext.Provider value={{ state, dispatch }}>
583→      {children}
584→    </SketchContext.Provider>
585→  );
586→}
587→
588→export function useSketch() {
589→  const ctx = useContext(SketchContext);
590→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
591→  const { state, dispatch } = ctx;
592→
593→  const getPart = useCallback(
594→    (partId) => state.project.parts.find((p) => p.id === partId) || null,
595→    [state.project.parts]
596→  );
597→
598→  const getAssembly = useCallback(
599→    (assemblyId) => state.project.assemblies.find((a) => a.id === assemblyId) || null,
600→    [state.project.assemblies]
601→  );
602→
603→  const getPartsForAssembly = useCallback(
604→    (assemblyId) => state.project.parts.filter((p) => p.assemblyId === assemblyId),
605→    [state.project.parts]
606→  );
607→
608→  const getChildParts = useCallback(
609→    (parentId) => state.project.parts.filter((p) => p.parentId === parentId),
610→    [state.project.parts]
611→  );
612→
613→  return {
614→    project: state.project,
615→    isDirty: state.isDirty,
616→    canUndo: state.history.length > 0,
617→    canRedo: state.future.length > 0,
618→    dispatch,
619→    getPart,
620→    getAssembly,
621→    getPartsForAssembly,
622→    getChildParts,
623→  };
624→}
