  border-color: rgba(184, 134, 11, 0.25);
  box-shadow: 0 0 0 1px rgba(184, 134, 11, 0.08), 0 1px 3px rgba(184, 134, 11, 0.12);
}

.toolBtnActive:hover {
  background: rgba(184, 134, 11, 0.15);
}

.toolBtnActive:active {
  transform: scale(0.96);
  box-shadow: var(--shadow-pressed);
}

.toolIcon {
  width: 18px;
  height: 18px;
  display: block;
}

.toggleBtn {
  composes: btn;
  opacity: 0.5;
}

.toggleBtn.toggleActive {
  opacity: 1;
  background: rgba(184, 134, 11, 0.1);
  color: var(--color-workspace-sketch, #B8860B);
  border-color: rgba(184, 134, 11, 0.25);
  box-shadow: 0 0 0 1px rgba(184, 134, 11, 0.08), 0 1px 3px rgba(184, 134, 11, 0.12);
}

.toggleBtn.toggleActive:hover {
  background: rgba(184, 134, 11, 0.15);
}

.spacer {
  flex: 1;
}

.dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  z-index: 100;
  min-width: 160px;
  background: var(--color-surface-elevated, #fff);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-lg);
  padding: 4px 0;
  margin-top: 4px;
}

.dropdownItem {
  display: block;
  width: 100%;
  padding: 8px 12px;
  text-align: left;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-text-primary);
  background: transparent;
  border: none;
  cursor: pointer;
  transition: background var(--duration-fast);
}

.dropdownItem:hover {
  background: rgba(0, 0, 0, 0.04);
}

@media (max-width: 900px) {
  .toolbar {
    gap: var(--space-xs);
    padding: var(--space-xs) var(--space-sm);
  }
  .group {
    padding: 0 var(--space-xs);
  }
  .toolPalette {
    padding: 0 var(--space-xs);
  }
  .groupLabel {
    display: none;
  }
}

