  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  background: var(--color-surface-elevated);
  border: 1px solid var(--color-border);
  color: var(--color-text-secondary);
  cursor: pointer;
  opacity: 0.7;
  transition: opacity var(--duration-fast), background var(--duration-fast), transform var(--duration-micro) var(--ease-tactile);
