  3→import { SketchEditorProvider, useSketchEditor } from './app/SketchEditorProvider';
  4→import SketchToolbar from './ui/SketchToolbar';
  5→import SketchSidebar from './ui/SketchSidebar';
  6→import SketchCanvas from './renderers/SketchCanvas';
  7→import SketchPropertiesPanel from './ui/SketchPropertiesPanel';
  8→import { saveSketchProject, loadSketchProject, listSketchProjects, deleteSketchProject } from './persistence/sketchStorage';
  9→import { exportSketchProjectFile, openSketchProjectFile, importSketchProjectFile, isFilePickerAbortError } from './persistence/sketchFileTransfer';
 10→import { useSketchAutosave } from './persistence/useSketchAutosave';
 11→import Modal from '@/ui/Modal';
 12→import TemplateDialog from './ui/TemplateDialog';
 13→import { generateId } from '@/domain/ids';
 14→import styles from './SketchWorkspace.module.css';
 15→
 16→const SketchPreviewPanel = lazy(() => import('./renderers/SketchPreviewPanel'));
 17→const SketchSheetCanvas = lazy(() => import('./renderers/SketchSheetCanvas'));
 18→
 19→const SketchProjectContext = createContext(null);
 20→
 21→export function useSketchProject() {
 22→  const ctx = useContext(SketchProjectContext);
 23→  if (!ctx) throw new Error('useSketchProject must be used within SketchWorkspace');
 24→  return ctx;
 25→}
 26→
 27→function SketchLoadModal({ onClose }) {
 28→  const { project, dispatch } = useSketch();
 29→  const [savedProjects, setSavedProjects] = useState([]);
 30→  const [loading, setLoading] = useState(true);
 31→  const importInputRef = useRef(null);
 32→  const { setFileHandle } = useSketchProject();
 33→
 34→  useEffect(() => {
 35→    listSketchProjects().then((list) => {
 36→      setSavedProjects(list);
 37→      setLoading(false);
 38→    });
 39→  }, []);
 40→
 41→  const handleOpenFile = async () => {
 42→    try {
 43→      const result = await openSketchProjectFile();
 44→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 45→      setFileHandle(result.fileHandle || null);
 46→      onClose();
 47→    } catch (err) {
 48→      if (!isFilePickerAbortError(err)) {
 49→        console.error('Failed to open sketch file:', err);
 50→      }
 51→    }
 52→  };
 53→
 54→  const handleImportFile = async (e) => {
 55→    const file = e.target.files?.[0];
 56→    if (!file) return;
 57→    try {
 58→      const result = await importSketchProjectFile(file);
 59→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 60→      setFileHandle(null);
 61→      onClose();
 62→    } catch (err) {
 63→      console.error('Failed to import sketch file:', err);
 64→    } finally {
 65→      e.target.value = '';
 66→    }
 67→  };
 68→
 69→  const handleLoadDraft = async (id) => {
 70→    try {
 71→      const result = await loadSketchProject(id);
 72→      if (result) {
 73→        dispatch({ type: 'SKETCH_LOAD', project: result.project });
 74→        setFileHandle(null);
 75→        onClose();
 76→      }
 77→    } catch (err) {
 78→      console.error('Failed to load sketch draft:', err);
 79→    }
 80→  };
 81→
 82→  const handleDeleteDraft = async (id, name) => {
 83→    if (!window.confirm(`Delete "${name}"?`)) return;
 84→    await deleteSketchProject(id);
 85→    setSavedProjects((prev) => prev.filter((p) => p.id !== id));
 86→  };
 87→
 88→  return (
 89→    <Modal title="Open Sketch Project" onClose={onClose}>
 90→      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', minWidth: '360px' }}>
 91→        <div style={{ display: 'flex', gap: '8px' }}>
 92→          <button
 93→            onClick={handleOpenFile}
 94→            style={{
 95→              flex: 1, padding: '10px 16px', borderRadius: '6px', border: '1px solid var(--color-border)',
 96→              background: 'var(--color-panel-bg)', cursor: 'pointer', fontFamily: 'var(--font-ui)', fontSize: '13px',
 97→            }}
 98→          >
 99→            Open Project File...
100→          </button>
101→          <button
102→            onClick={() => importInputRef.current?.click()}
103→            style={{
104→              flex: 1, padding: '10px 16px', borderRadius: '6px', border: '1px solid var(--color-border)',
105→              background: 'var(--color-panel-bg)', cursor: 'pointer', fontFamily: 'var(--font-ui)', fontSize: '13px',
106→            }}
107→          >
108→            Import File...
109→          </button>
110→          <input
111→            ref={importInputRef}
112→            type="file"
113→            accept=".json"
114→            onChange={handleImportFile}
115→            style={{ display: 'none' }}
116→          />
117→        </div>
118→
119→        <div>
120→          <h4 style={{ margin: '0 0 8px', fontSize: '12px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--color-text-secondary)' }}>
121→            Browser Drafts
122→          </h4>
123→          {loading ? (
124→            <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)' }}>Loading...</p>
125→          ) : savedProjects.length === 0 ? (
126→            <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)' }}>No saved drafts.</p>
127→          ) : (
128→            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', maxHeight: '300px', overflowY: 'auto' }}>
129→              {savedProjects.map((entry) => (
130→                <div
131→                  key={entry.id}
132→                  style={{
133→                    display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 10px',
134→                    borderRadius: '6px', border: '1px solid var(--color-border)', background: 'var(--color-panel-bg)',
135→                  }}
136→                >
137→                  <div style={{ flex: 1, minWidth: 0 }}>
138→                    <div style={{ fontSize: '13px', fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
139→                      {entry.name || 'Untitled'}
140→                    </div>
141→                    {entry.savedAt && (
142→                      <div style={{ fontSize: '11px', color: 'var(--color-text-secondary)', marginTop: '2px' }}>
143→                        {new Date(entry.savedAt).toLocaleString()}
144→                      </div>
145→                    )}
146→                  </div>
147→                  <button
148→                    onClick={() => handleLoadDraft(entry.id)}
149→                    style={{
150→                      padding: '4px 12px', borderRadius: '4px', border: '1px solid var(--color-border)',
151→                      background: 'var(--color-panel-bg)', cursor: 'pointer', fontSize: '12px',
152→                    }}
153→                  >
154→                    Load
155→                  </button>
156→                  <button
157→                    onClick={() => handleDeleteDraft(entry.id, entry.name)}
158→                    style={{
159→                      padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--color-border)',
160→                      background: 'var(--color-panel-bg)', cursor: 'pointer', fontSize: '12px', color: 'var(--color-text-secondary)',
161→                    }}
162→                  >
163→                    Delete
164→                  </button>
165→                </div>
166→              ))}
167→            </div>
168→          )}
169→        </div>
170→      </div>
171→    </Modal>
172→  );
173→}
174→
175→function SketchInner() {
176→  const { project, isDirty, dispatch } = useSketch();
177→  const { maximizedPanel, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
178→  const [showLoadModal, setShowLoadModal] = useState(false);
179→  const [showTemplateDialog, setShowTemplateDialog] = useState(false);
180→  const [fileHandle, setFileHandle] = useState(null);
181→
182→  // Autosave
183→  useSketchAutosave(project, isDirty, dispatch);
184→
185→  // beforeunload warning
186→  useEffect(() => {
187→    const handler = (e) => {
188→      if (isDirty) {
189→        e.preventDefault();
190→        e.returnValue = '';
191→      }
192→    };
193→    window.addEventListener('beforeunload', handler);
194→    return () => window.removeEventListener('beforeunload', handler);
195→  }, [isDirty]);
196→
197→  // Ctrl+S file save
198→  useEffect(() => {
199→    const handler = async (e) => {
200→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
201→        e.preventDefault();
202→        try {
203→          const result = await exportSketchProjectFile(project, { fileHandle });
204→          if (result.fileHandle) setFileHandle(result.fileHandle);
205→          await saveSketchProject(project);
206→          dispatch({ type: 'MARK_SAVED' });
207→        } catch (err) {
208→          if (!isFilePickerAbortError(err)) {
209→            console.error('Save failed:', err);
210→          }
211→        }
212→      }
213→    };
214→    window.addEventListener('keydown', handler);
215→    return () => window.removeEventListener('keydown', handler);
216→  }, [project, fileHandle, dispatch]);
217→
218→  // If active sheet was deleted, revert to model mode
219→  useEffect(() => {
220→    if (workspaceMode === 'sheet' && activeSheetId) {
221→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
222→      if (!sheetExists) {
223→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
224→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
225→      }
226→    }
227→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
228→
229→  const handleNew = useCallback(() => {
230→    if (isDirty && !window.confirm('You have unsaved changes. Start a new project?')) return;
231→    dispatch({ type: 'SKETCH_NEW' });
232→    setFileHandle(null);
233→  }, [isDirty, dispatch]);
234→
235→  const handleSave = useCallback(async () => {
236→    try {
237→      const result = await exportSketchProjectFile(project, { fileHandle });
238→      if (result.fileHandle) setFileHandle(result.fileHandle);
239→      await saveSketchProject(project);
240→      dispatch({ type: 'MARK_SAVED' });
241→    } catch (err) {
242→      if (!isFilePickerAbortError(err)) {
243→        console.error('Save failed:', err);
244→      }
245→    }
246→  }, [project, fileHandle, dispatch]);
247→
248→  const handleLoadClick = useCallback(() => {
249→    setShowLoadModal(true);
250→  }, []);
251→
252→  const isSheetMode = workspaceMode === 'sheet';
253→
254→  return (
255→    <SketchProjectContext.Provider value={{ handleNew, handleSave, handleLoadClick, fileHandle, setFileHandle, showTemplateDialog, setShowTemplateDialog }}>
256→      <div className={styles.layout}>
257→        <div className={styles.toolbar}>
258→          <SketchToolbar />
259→        </div>
