import { SKETCH_MIN_ZOOM, SKETCH_MAX_ZOOM, SKETCH_ZOOM_FACTOR } from '../domain/defaults';
import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
import { getViewLabel, viewToModelPosition } from '../domain/viewProjection';
import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
import { createPartPlaceHandler } from '../editor/handlers/partPlaceHandler';
import { createDimensionHandler } from '../editor/handlers/dimensionHandler';
import CompassOverlay from '@/ui/CompassOverlay';
import { CenterViewIcon, ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
